import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{o as d,c as e,e as a}from"./app-8181ed57.js";const n={},r=a(`<p>很多函数都有自己的很多方法，其中有些方法的功能类似，但是其复杂度有时却大不相同</p><p>本节我们将引入一个新模块 <code>timeit</code> ，其功能是来测试一小段 <code>Python</code> 代码的执行速度。</p><h3 id="_1、timeit" tabindex="-1"><a class="header-anchor" href="#_1、timeit" aria-hidden="true">#</a> 1、timeit</h3><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">timeit</span><span class="token punctuation">.</span>Timer<span class="token punctuation">(</span>stmt<span class="token operator">=</span><span class="token string">&#39;pass&#39;</span><span class="token punctuation">,</span> setup<span class="token operator">=</span><span class="token string">&#39;pass&#39;</span><span class="token punctuation">,</span>timer<span class="token operator">=</span><span class="token operator">&lt;</span>timer function<span class="token operator">&gt;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><p><code>Timer</code> 是测量小段代码执行速度的类</p></li><li><p><code>stmt</code> 是要测试的代码语句 (<code>statment</code>), 字符串类型,</p></li><li><p><code>setup</code> 是运行代码时需要的设置 , 字符串类型, 就是从 <code>__main__</code> 引入需要的是的方法名</p></li><li><p><code>timer</code> 参数是一个定时器函数, 与平台有关, 不用去管</p></li><li><p><code>timeit.Timer.timeit(numer=1000000)</code>，<code>numer</code>-&gt; 测算次数, 返回平均耗时, 一个 <code>float</code> 类型的秒数</p></li></ul><h4 id="部分测试示例" tabindex="-1"><a class="header-anchor" href="#部分测试示例" aria-hidden="true">#</a> 部分测试示例</h4><figure><img src="https://img.bookandmusic.cn/blog/2022/01/p4tWrN.png" alt="p4tWrN" tabindex="0" loading="lazy"><figcaption>p4tWrN</figcaption></figure><h4 id="测试结果" tabindex="-1"><a class="header-anchor" href="#测试结果" aria-hidden="true">#</a> 测试结果</h4><figure><img src="https://img.bookandmusic.cn/blog/2022/01/Pjy5rN.png" alt="Pjy5rN" tabindex="0" loading="lazy"><figcaption>Pjy5rN</figcaption></figure><h3 id="_2、list-的内置函数时间复杂度" tabindex="-1"><a class="header-anchor" href="#_2、list-的内置函数时间复杂度" aria-hidden="true">#</a> 2、list 的内置函数时间复杂度</h3><table><thead><tr><th>方法</th><th>复杂度</th><th>简介</th></tr></thead><tbody><tr><td>index[x]</td><td>O(1)</td><td>索引</td></tr><tr><td>index assignment</td><td>O(1)</td><td>索引赋值</td></tr><tr><td>append</td><td>O(1)</td><td>尾部追加</td></tr><tr><td>pop()</td><td>O(1)</td><td>尾部弹出</td></tr><tr><td>pop(i)</td><td>O(n)</td><td>指定位置弹出 n 列表长度, 最坏时间复杂度</td></tr><tr><td>insert(i, item)</td><td>O(n)</td><td>指定位置添加</td></tr><tr><td>del operator</td><td>O(n)</td><td>删除, 代表一个一个元素去清空</td></tr><tr><td>iteration</td><td>O(n)</td><td>迭代</td></tr><tr><td>contains(in)</td><td>O(n)</td><td>看谁是否在列表中, 需要遍历</td></tr><tr><td>get slice[x:y]</td><td>O(k)</td><td>取切片, 从 x 取到 y, 一次定位到 x, 然后取到 y ,x 和 y 之间有多少就是 k</td></tr><tr><td>del slice</td><td>O(n)</td><td>删除切片 删除位置之后, 后面的元素都需要往前移动</td></tr><tr><td>set slice</td><td>O(k)</td><td>设置切片, li[0:3] = [1, 2, 3, 4]k 是补充的东西数量</td></tr><tr><td>reverse</td><td>O(n)</td><td>置返</td></tr><tr><td>concatenate</td><td>O(k)</td><td>代表使用的 +, 把两个列表加到一起, k 是第二个列表中的元素</td></tr><tr><td>sort</td><td>O(nlogn)</td><td>排序</td></tr><tr><td>multiply</td><td>O(nk)</td><td>相乘 li=[1, 2] -&gt; n li * 10 -&gt; k</td></tr></tbody></table><h3 id="_3、dict-的内置函数时间复杂度" tabindex="-1"><a class="header-anchor" href="#_3、dict-的内置函数时间复杂度" aria-hidden="true">#</a> 3、dict 的内置函数时间复杂度</h3><table><thead><tr><th>方法</th><th>复杂度</th><th>简介</th></tr></thead><tbody><tr><td>copy</td><td>O(n)</td><td>复制</td></tr><tr><td>get item</td><td>O(1)</td><td>取</td></tr><tr><td>set item</td><td>O(1)</td><td>设置</td></tr><tr><td>delete item</td><td>O(1)</td><td>删除键</td></tr><tr><td>contains(in)</td><td>O(1)</td><td>包含</td></tr><tr><td>iteration</td><td>O(n)</td><td>迭代</td></tr></tbody></table>`,13),i=[r];function s(o,c){return d(),e("div",null,i)}const h=t(n,[["render",s],["__file","常见函数的时间复杂度-b4e401cd.html.vue"]]);export{h as default};
